const b = $input.first().json.body || $input.first().json;
const allowed = new Set(['won','lost','too_early','not_real','real_but_uncontactable','ignored']);
const status = String(b.status || '').toLowerCase();
const signalId = String(b.signalId || b.id || '').trim();
if (!signalId || !allowed.has(status)) {
  throw new Error('signalId + status required; status must be ' + [...allowed].join(','));
}
return [{ json: { ok: true, signalId, status, note: b.note || '', source: b.source || 'webhook' } }];

const fs = require('fs');
const path = require('path');
const vaultPath = 'C:/Users/manaz/Desktop/JobFilter/JobFilterV1/Obsidian_Memory/Obsidian_Vault';
const val = $('Validate Payload').item.json;
const apiRes = $input.first().json;
const now = new Date();
const slug = String(val.signalId).toLowerCase().replace(/[^a-z0-9]+/g,'-');
const dir = path.join(vaultPath, 'JobFilter', 'Outcomes');
fs.mkdirSync(dir, { recursive: true });
const file = path.join(dir, slug + '.md');
const md = `---
type: outcome
signal_id: ${val.signalId}
status: ${val.status}
logged_at: ${now.toISOString()}
source: ${val.source}
tags: [jobfilter, outcome, ${val.status}]
---

# Outcome — ${val.signalId}

**Status:** ${val.status}
**Logged:** ${now.toISOString()}

## Note
${val.note || '_none_'}

## API response

\`\`\`json
${JSON.stringify(apiRes, null, 2)}
\`\`\`
`;
fs.writeFileSync(file, md);
return [{ json: { ok: true, signalId: val.signalId, status: val.status, file } }];
